-- 查询重发次数最多的帖子
SELECT title, MAX(repost_count) as repost_count FROM thread_follows GROUP BY url ORDER BY repost_count DESC LIMIT 1;

-- 查询重发次数最多的作者
SELECT author, SUM(repost_count) as total_reposts FROM thread_follows GROUP BY author ORDER BY total_reposts DESC LIMIT 1;

